import {
  ChangeDetectionStrategy,
  ChangeDetectorRef,
  Component,
  OnInit,
} from '@angular/core';
import { BaseClassTemplate } from '../core/class';
import { BreakpointObserver, Breakpoints } from '@angular/cdk/layout';

@Component({
  selector: 'aam-feature',
  templateUrl: './feature.component.html',
  styleUrls: ['./feature.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class FeatureComponent extends BaseClassTemplate implements OnInit {
  constructor(public cdr: ChangeDetectorRef, public bpo: BreakpointObserver) {
    super();
    this._cdr = cdr;
    this._template.DATA.subscribe({
      next: (data) => {
        console.log({ DATA: (this.DATA = data) });
        setTimeout(() => {
          this._cdr.detectChanges();
        }, 100);
      },
    });
  }
  ngOnInit(): void {
    this.bpoInit();
    // inorder to refresh / reset the list
    // (click)="lb.reset(); lb.refresh()"
    // (click)="lb.refresh()"
  }

  public cols: number;
  public SM = false;
  public MD = false;
  public LG = false;
  public bpoInit() {
    this.bpo
      .observe([Breakpoints.XSmall,Breakpoints.Small, Breakpoints.Medium, Breakpoints.Large, Breakpoints.XLarge])
      .subscribe((result) => {
        const bp = result.breakpoints;
        this.SM = this.MD = this.LG = false;
        if (bp[Breakpoints.XSmall] || bp[Breakpoints.Small]) this.SM = true;
        else if (bp[Breakpoints.Medium]) this.MD = true;
        else this.LG = true;
        this.cdr.detectChanges();
      });
  }


}
