import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { FeatureComponent } from './feature.component';

const routes: Routes = [
  {
    path: '',
    component: FeatureComponent,
    children: [
      {
        path: '',
        redirectTo: 'user',
        pathMatch: 'full',
      },
      {
        path: 'user',
        loadChildren: () =>
          import('./userz/userz.module').then((m) => m.UserzModule),
      },
      {
        path: 'account-in',
        loadChildren: () =>
          import('./account-in/account-in.module').then((m) => m.AccountInModule),
      },
      {
        path: 'account-out',
        loadChildren: () =>
          import('./account-out/account-out.module').then((m) => m.AccountOutModule),
      },
      {
        path: 'education',
        loadChildren: () =>
          import('./education/education.module').then((m) => m.EducationModule),
      },
      {
        path: 'exam',
        loadChildren: () =>
          import('./education-exam/education-exam.module').then((m) => m.EducationExamModule),
      },
      {
        path: 'syllabus',
        loadChildren: () =>
          import('./education-syllabus/education-syllabus.module').then((m) => m.EducationSyllabusModule),
      },
      {
        path: 'file-upload',
        loadChildren: () =>
          import('./file-upload/file-upload.module').then((m) => m.FileUploadModule),
      },
      {
        path: 'notification',
        loadChildren: () =>
          import('./notification/notification.module').then((m) => m.NotificationModule),
      },
    ],
  },
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule],
})
export class FeatureRoutingModule {}
